		default:
			respondError(w, http.StatusMethodNotAllowed, "method not allowed")
		}
		return
	}

	// Route: /books/{id}
	if strings.HasPrefix(r.URL.Path, "/books/") {
		id, err := extractID(r.URL.Path, "/books/")
		if err != nil {
			respondError(w, http.StatusBadRequest, "invalid book ID")
