		switch r.Method {
		case http.MethodGet:
			h.getBook(w, r, id)
		case http.MethodPut:
			h.updateBook(w, r, id)
		case http.MethodDelete:
			h.deleteBook(w, r, id)
		default:
			respondError(w, http.StatusMethodNotAllowed, "method not allowed")
		}
		return
	}

	respondError(w, http.StatusNotFound, "not found")
}

